#!/usr/bin/env python3
# AUTHORIZED OWNED-IDENTITY ONLY. Offline mock of the passive breach/paste credential-exposure check.
# Demonstrates the k-anonymity SHA1-prefix lookup pattern (as used by HIBP) WITHOUT contacting any service.
import hashlib

fake_breach = {hashlib.sha1(p.encode()).hexdigest().upper(): c for p, c in {
    'Password123!': 4521, 'Summer2024': 99, 'CorrectHorse': 1}.items()}

owned_candidates = ['Password123!', 'Tr0ub4dor&3-unique-xyz']

exposed = 0
for cand in owned_candidates:
    h = hashlib.sha1(cand.encode()).hexdigest().upper()
    prefix, suffix = h[:5], h[5:]
    bucket = {k[5:]: v for k, v in fake_breach.items() if k[:5] == prefix}
    if suffix in bucket:
        print('[!] EXPOSED: candidate matches breach corpus, seen %d times (prefix %s)' % (bucket[suffix], prefix))
        exposed += 1
    else:
        print('[ ] not found: prefix %s' % prefix)
print('RESULT: VULNERABLE (owned credential found in breach corpus)' if exposed else 'RESULT: PASS (no exposure in mock corpus)')
